// Helper method to handle exceptions consistently
    private void handleException(final String message, final Exception ex, final String context) {
        log.error("{}: {} ", message, ex.getMessage());
        throw new CpsStartupException(message, context + ": " + ex.getMessage());
    }

    // Helper method to log warnings for already defined exceptions
    private void logWarning(final String message, final String context) {
        log.warn(message, context);
    }

